<?php include '_top.php';
if($_SERVER['REQUEST_METHOD']==='POST') $pdo->prepare("INSERT INTO horarios_doctores(id_doctor,dia_semana,hora_inicio,hora_fin) VALUES(?,?,?,?)")->execute([$_POST['id_doctor'],$_POST['dia'],$_POST['inicio'],$_POST['fin']]);
$docs=$pdo->query("SELECT d.id_doctor,u.nombre FROM doctores d JOIN usuarios u ON d.id_usuario=u.id_usuario")->fetchAll();
$hor=$pdo->query("SELECT h.*,u.nombre doctor FROM horarios_doctores h JOIN doctores d ON h.id_doctor=d.id_doctor JOIN usuarios u ON d.id_usuario=u.id_usuario ORDER BY doctor,dia_semana")->fetchAll();
?><h1>Horarios de doctores</h1><div class="box form"><form method="post"><select name="id_doctor"><?php foreach($docs as $d): ?><option value="<?=$d['id_doctor']?>"><?=$d['nombre']?></option><?php endforeach; ?></select><select name="dia"><option>Lunes</option><option>Martes</option><option>Miércoles</option><option>Jueves</option><option>Viernes</option><option>Sábado</option><option>Domingo</option></select><input type="time" name="inicio" required><input type="time" name="fin" required><button class="btn">Agregar</button></form></div><table><tr><th>Doctor</th><th>Día</th><th>Inicio</th><th>Fin</th></tr><?php foreach($hor as $h): ?><tr><td><?=$h['doctor']?></td><td><?=$h['dia_semana']?></td><td><?=$h['hora_inicio']?></td><td><?=$h['hora_fin']?></td></tr><?php endforeach; ?></table><?php include '_bottom.php'; ?>
